'use client';

import * as React from "react";
import * as TogglePrimitive from "@radix-ui/react-toggle";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "../../lib/utils";

const toggleButtonVariants = cva(
  "uii:inline-flex uii:items-center uii:justify-center uii:gap-2 uii:whitespace-nowrap uii:rounded-sm uii:text-sm uii:font-medium uii:transition-[color,box-shadow] uii:disabled:pointer-events-none uii:disabled:opacity-50 uii:outline-none uii:focus-visible:border-ring uii:focus-visible:ring-ring/50 uii:focus-visible:ring-[3px] uii:cursor-pointer uii:border uii:shadow-xs",
  {
    variants: {
      variant: {
        default:
          "uii:data-[state=on]:bg-primary uii:data-[state=on]:text-primary-foreground uii:data-[state=on]:border-primary uii:data-[state=off]:border-input uii:data-[state=off]:bg-background uii:data-[state=off]:hover:bg-accent uii:data-[state=off]:hover:text-accent-foreground",
        outline:
          "uii:data-[state=on]:bg-accent uii:data-[state=on]:text-accent-foreground uii:data-[state=on]:border-input uii:data-[state=off]:border-input uii:data-[state=off]:bg-background uii:data-[state=off]:hover:bg-accent uii:data-[state=off]:hover:text-accent-foreground",
        secondary:
          "uii:data-[state=on]:bg-secondary uii:data-[state=on]:text-secondary-foreground uii:data-[state=on]:border-transparent uii:data-[state=off]:border-input uii:data-[state=off]:bg-background uii:data-[state=off]:hover:bg-secondary/80 uii:data-[state=off]:hover:text-secondary-foreground",
        ghost:
          "uii:data-[state=on]:bg-accent uii:data-[state=on]:text-accent-foreground uii:data-[state=on]:border-transparent uii:data-[state=off]:border-transparent uii:data-[state=off]:hover:bg-accent uii:data-[state=off]:hover:text-accent-foreground",
      },
      size: {
        default: "uii:h-9 uii:px-4 uii:py-2 uii:has-[>svg]:px-3",
        sm: "uii:h-8 uii:rounded-sm uii:gap-1.5 uii:px-3 uii:has-[>svg]:px-2.5",
        lg: "uii:h-10 uii:rounded-sm uii:px-6 uii:has-[>svg]:px-4",
        icon: "uii:size-9",
        iconSm: "uii:size-6 uii:text-base",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  }
);

type ToggleButtonProps = React.ComponentProps<typeof TogglePrimitive.Root> &
  VariantProps<typeof toggleButtonVariants>;

function ToggleButton({ className, variant, size, ...props }: ToggleButtonProps) {
  return (
    <TogglePrimitive.Root
      data-slot="toggle-button"
      className={cn(toggleButtonVariants({ variant, size, className }))}
      {...props}
    />
  );
}

export { ToggleButton, toggleButtonVariants };
